#version 300 es
precision highp float;

// VisualSynth uniforms
uniform float uTime;
uniform float uFrame;
uniform float uFps;
uniform float uRms;

// Audio uniforms
uniform float audioLow;      // bass
uniform float audioLowSmooth; // bass_att
uniform float audioMid;      // mid
uniform float audioMidSmooth; // mid_att
uniform float audioHigh;     // treb
uniform float audioHighSmooth; // treb_att

// Screen uniforms
uniform float uAspectX;
uniform float uAspectY;
uniform vec2 uAspect;
uniform vec2 uTexSize;

// Random values
uniform vec2 uRandomPreset;
uniform vec2 uRandomFrame;

// Input from vertex shader
in vec2 vUv;
in float vRadius;
in float vAngle;

// Output
out vec4 fragColor;

// Textures
uniform sampler2D sampler_main;
uniform sampler2D sampler_noise_lq;
uniform sampler2D sampler_noise_mq;
uniform sampler2D sampler_noise_hq;
uniform sampler2D sampler_blur1;
uniform sampler2D sampler_blur2;
uniform sampler2D sampler_blur3;

// Helper functions
float clamp01(float x) { return clamp(x, 0.0, 1.0); }
vec2 clamp01(vec2 x) { return clamp(x, vec2(0.0), vec2(1.0)); }
vec3 clamp01(vec3 x) { return clamp(x, vec3(0.0), vec3(1.0)); }
vec4 clamp01(vec4 x) { return clamp(x, vec4(0.0), vec4(1.0)); }

// Texture helper functions
vec4 GetPixel(vec2 uv) { return texture(sampler_main, uv); }
vec4 GetBlur1(vec2 uv) { return texture(sampler_blur1, uv); }
vec4 GetBlur2(vec2 uv) { return texture(sampler_blur2, uv); }
vec4 GetBlur3(vec2 uv) { return texture(sampler_blur3, uv); }


void main() {
  vec4 ret = vec4(0.0);
  vec2 uv = vUv;
  float rad = vRadius;

    #define PI2 6.28318530718
    #define MAX_ITER 5
    #define INV_MAX_ITER 0.2  // 1.0/MAX_ITER

    const float time2 = uTime * 0.02;
    vUv = vUvOriginal;

    // Pattern coordinates - optimized to remove fmod when not needed
    const vec2 p = vUv * PI2 - 250.0;
    vec2 i = p;
    float c = 1.0;
    const float brightness = 0.005;
    const float invBrightness = 200.0;  // 1.0/brightness

    // Precompute uTime components
    const float t0 = time2;
    const float t1 = time2 + uTime;

    // Fractal iteration loop - unrolled and optimized
    for (int n = 0; n < MAX_ITER; n++) {
        const float t = t0 * (1.0 - (3.5 / (float(n)+1.0)));
        const float sin_t = sin(t);
        const float cos_t = cos(t);

        // Update i with optimized trig operations
        const vec2 i_plus_t = i + uTime/2;
        const vec2 i_minus_t = i - t;

        i.x = p.x + cos_t*cos(i_minus_t.x) - sin_t*sin(i_minus_t.x)
                   + sin_t*cos(i_plus_t.y) + cos_t*sin(i_plus_t.y);
        i.y = p.y + sin_t*cos(i_minus_t.y) - cos_t*sin(i_minus_t.y)
                   + cos_t*cos(i_plus_t.x) - sin_t*sin(i_plus_t.x);

        // Optimized denominator calculations
        const float sin_ixt = sin(i.x + t);
        const float cos_iyt = cos(i.y + t);
        const float denom = sin_ixt * invBrightness;
        const float denom2 = cos_iyt * invBrightness;

        // Optimized length calculation
        const vec2 pd = vec2(p.x/denom, p.y/denom2);
        c += inversesqrt(dot(pd, pd));  // Faster than 1.0/length()
    }

    // Post-processing
    c *= INV_MAX_ITER;  // Faster than division
    c = 1.17 - pow(c, 1.4);
    const vec3 colour = pow(abs(c), 8.0);
    ret = vec4(colour, 1.0);

  fragColor = ret;
}

